cds-views-012.codeExamples:
" S/4HANA VDM compliant custom interface view
@AbapCatalog.sqlViewName: 'ZI_CUSTORDER_V'
@AbapCatalog.compiler.compareFilter: true
@AbapCatalog.preserveKey: true
@AccessControl.authorizationCheck: #CHECK
@EndUserText.label: 'Customer Order Interface View'
@VDM.viewType: #BASIC
define view ZI_CustomerOrder
  as select from vbak
  association [0..1] to kna1 as _Customer
    on $projection.SoldToParty = _Customer.kunnr
  association [0..*] to vbap as _Items
    on $projection.SalesOrder = _Items.vbeln
{
  key vbak.vbeln as SalesOrder,
      vbak.kunnr  as SoldToParty,
      vbak.audat  as OrderDate,
      vbak.netwr  as NetValue,
      vbak.waerk  as Currency,
      _Customer,
      _Items
}

" S/4HANA consumption view for Fiori
@AbapCatalog.sqlViewName: 'ZC_CUSTORDER_V'
@AccessControl.authorizationCheck: #CHECK
@EndUserText.label: 'Customer Order List - Fiori'
@VDM.viewType: #CONSUMPTION
@OData.publish: true
@UI.headerInfo: {
  typeName: 'Sales Order',
  typeNamePlural: 'Sales Orders'
}
define view ZC_CustomerOrderList
  as select from ZI_CustomerOrder
{
  @UI.lineItem: [{ position: 10, label: 'Order No' }]
  @UI.selectionField: [{ position: 10 }]
  key SalesOrder,
  @UI.lineItem: [{ position: 20, label: 'Customer' }]
  @UI.selectionField: [{ position: 20 }]
      SoldToParty,
  @UI.lineItem: [{ position: 30, label: 'Date' }]
      OrderDate,
  @UI.lineItem: [{ position: 40, label: 'Net Value' }]
  @Semantics.amount.currencyCode: 'Currency'
      NetValue,
      Currency
}

