" Interface view - ZI_ prefix
@VDM.viewType: #BASIC
define view ZI_PurchaseOrder
  as select from ekko
{ key ekko.ebeln as PurchaseOrder,
      ekko.lifnr  as Supplier,
      ekko.bedat  as OrderDate }

" Consumption view - ZC_ prefix
@VDM.viewType: #CONSUMPTION
@OData.publish: true
define view ZC_PurchaseOrderList
  as select from ZI_PurchaseOrder
{
  @UI.lineItem: [{ position: 10 }]
  key PurchaseOrder,
  @UI.lineItem: [{ position: 20 }]
      Supplier
}

" Simple annotation-based OData service
@OData.publish: true
@AbapCatalog.sqlViewName: 'ZC_VENDOR_V'
@EndUserText.label: 'Vendor List'
define view ZC_VendorList
  as select from lfa1
{
  @UI.lineItem: [{ position: 10 }]
  @UI.selectionField: [{ position: 10 }]
  key lfa1.lifnr as Vendor,
  @UI.lineItem: [{ position: 20 }]
      lfa1.name1  as VendorName,
  @UI.lineItem: [{ position: 30 }]
      lfa1.land1  as Country
}
" After activation: service ZC_VENDORLIST_CDS
" available at /sap/opu/odata/sap/ZC_VENDORLIST_CDS/

" ABAP CDS - defined in Eclipse ADT, transported via CTS
" File: ZI_FINANCIAL_DATA.ddls (in ABAP package)
@AbapCatalog.sqlViewName: 'ZI_FINDATA_V'
@AccessControl.authorizationCheck: #CHECK
@Analytics.dataCategory: #CUBE
define view ZI_FinancialData
  as select from acdoca
{ key acdoca.rbukrs as CompanyCode,
      sum(acdoca.hsl) as Amount,
      acdoca.rhcur    as Currency
} group by acdoca.rbukrs, acdoca.rhcur

" vs HANA Calculation View: defined in HANA Studio
" outside ABAP, no CTS transport, no DCL support

@Analytics.dataCategory: #CUBE
@VDM.viewType: #BASIC
@AbapCatalog.sqlViewName: 'ZI_REVCUBE_V'
define view ZI_RevenueCube
  as select from acdoca
  association [0..1] to I_CompanyCode as _CompanyCode
    on $projection.CompanyCode = _CompanyCode.CompanyCode
{
  key acdoca.rldnr  as Ledger,
  key acdoca.rbukrs as CompanyCode,
  key acdoca.gjahr  as FiscalYear,
  key acdoca.prctr  as ProfitCenter,
  @Aggregation.default: #SUM
  @Semantics.amount.currencyCode: 'AmountCurrency'
      sum(acdoca.hsl) as Amount,
      acdoca.rhcur    as AmountCurrency,
      _CompanyCode
} group by acdoca.rldnr, acdoca.rbukrs,
           acdoca.gjahr, acdoca.prctr, acdoca.rhcur

" OLD - SE11 database view approach (avoid for new development)
" Created in SE11 as ZOLD_VENDOR_VIEW
" No annotations, no DCL, no OData support

" NEW - CDS View approach (S/4HANA standard)
@AbapCatalog.sqlViewName: 'ZI_VENDOR_V'  " legacy, use VIEW ENTITY in newer syntax
@AccessControl.authorizationCheck: #CHECK
@VDM.viewType: #BASIC
define view ZI_VendorData
  as select from lfa1
{
  key lfa1.lifnr as Vendor,        " explicit fields - no SELECT *
      lfa1.name1  as VendorName,
      lfa1.land1  as Country,
      lfa1.ktokk  as AccountGroup
}
" Advantages: DCL security, OData possible, VDM compliant, transportable

" DANGEROUS - never in production
@AccessControl.authorizationCheck: #NOT_REQUIRED
define view ZI_PayrollData  " security hole!
  as select from pa0008
{ key pa0008.pernr, pa0008.lga01, pa0008.bet01 }

" CORRECT approach
@AccessControl.authorizationCheck: #CHECK
define view ZI_PayrollData
  as select from pa0008
{ key pa0008.pernr, pa0008.lga01, pa0008.bet01 }
" DCL: restrict by HR org assignment + ACTVT

" WRONG - amount without currency annotation
define view ZI_Invoice_Wrong ...
{
  key vbeln,
  netwr as NetValue,          " missing annotation!
  waerk as Currency
}

" RIGHT - proper semantic annotation pairing
define view ZI_Invoice_Right ...
{
  key vbeln,
  @Semantics.amount.currencyCode: 'Currency'  " references field name
      netwr as NetValue,
  @Semantics.currencyCode: true
      waerk as Currency
}
" Fiori now renders: 1,234.56 EUR (with symbol and formatting)

" OLD syntax - DEFINE VIEW (requires sqlViewName)
@AbapCatalog.sqlViewName: 'ZI_SALESORD_V'  " creates SE11 view
@AbapCatalog.compiler.compareFilter: true
define view ZI_SalesOrder
  as select from vbak
{ key vbak.vbeln as SalesOrder,
      vbak.kunnr  as Customer }
" Results in: SE11 view ZI_SALESORD_V + CDS view ZI_SalesOrder

" NEW syntax - DEFINE VIEW ENTITY (S/4HANA 2022+)
@AccessControl.authorizationCheck: #CHECK
@EndUserText.label: 'Sales Order Entity'
define view entity ZI_SalesOrderEntity
  as select from vbak
{ key vbak.vbeln as SalesOrder,
      vbak.kunnr  as Customer }
" Results in: only CDS view entity ZI_SalesOrderEntity
" No SE11 SQL view created — lighter weight, RAP compatible

